		id != externalDurabilityScenarioID &&
		id != externalCrashScenarioID {
		fatalf("unsupported scenario id %q", id)
	}

	fs := flag.NewFlagSet("scenario", flag.ExitOnError)
	impl := fs.String("impl", "", "implementation to run (go or rust)")
