			}
			if localOK && stateOK {
				return payload, polls, nil
			}
		}
		time.Sleep(200 * time.Millisecond)
	}
	if last == nil {
		last = map[string]any{}
	}
	return last, polls, fmt.Errorf("timed out waiting for local status convergence for folder %q", folder)
