		return metrics, fmt.Errorf("go shutdown request: %w", err)
	}
	metrics.ShutdownRequested = true
	if err := proc.wait(shutdownTimeout); err != nil {
		return metrics, fmt.Errorf("go daemon shutdown wait: %w", err)
	}
	return metrics, nil
}

