		"GET /rest/db/completion":           {"completion", "globalBytes", "needBytes", "globalItems", "needItems", "needDeletes", "sequence", "remoteState"},
		"GET /rest/db/file":                 {"folder", "file"},
		"GET /rest/db/ignores":              {"folder", "count", "patterns"},
