func main() {
	if len(os.Args) < 3 || os.Args[1] != "scenario" {
		fatalf(
			"usage: go run ./script/parity_external_soak.go scenario <%s|%s|%s|%s|%s|%s> --impl <go|rust>",
			daemonAPISurfaceScenarioID,
			externalSoakScenarioID,
