		if !ok {
			continue
		}
		id := strings.TrimSpace(stringField(entry, "deviceID"))
		if id == "" {
			id = strings.TrimSpace(stringField(entry, "id"))
		}
		if id == "" {
			continue
		}
		out = append(out, id)
